import { Controller, Get, Post, Body, Param, Patch, Delete, UseGuards, Query } from '@nestjs/common';
import { VulnerabilityService } from './vulnerability.service';
import { CreateVulnerabilityDto, UpdateVulnerabilityDto } from './dto/vulnerability.dto';
import { AuthGuard } from '../auth/guards/auth.guard';

@UseGuards(AuthGuard)
@Controller('vulnerabilities')
export class VulnerabilityController {
  constructor(
    private readonly vulnerabilityService: VulnerabilityService,
    private readonly exportService: ExportService,
  ) {}

  @Post()
  async create(@Body() dto: CreateVulnerabilityDto) {
    return this.vulnerabilityService.create(dto);
  }

  @Get()
  async findAll(@Query('targetId') targetId?: string, @Query('severity') severity?: string) {
    return this.vulnerabilityService.findAll(targetId, severity);
  }

  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.vulnerabilityService.findOne(id);
  }

  @Patch(':id')
  async update(@Param('id') id: string, @Body() dto: UpdateVulnerabilityDto) {
    return this.vulnerabilityService.update(id, dto);
  }

  @Delete(':id')
  async delete(@Param('id') id: string) {
    return this.vulnerabilityService.delete(id);
  }

  @Get('stats/summary')
  async getStats() {
    return this.vulnerabilityService.getStats();
  }

  @Get('export/csv')
  async exportToCSV(@Res() res: Response) {
    const vulnerabilities = await this.vulnerabilityService.findAll();
    const csv = this.exportService.exportVulnerabilitiesToCSV(vulnerabilities);

    res.setHeader('Content-Type', 'text/csv');
    res.setHeader('Content-Disposition', `attachment; filename="vulnerabilities_${Date.now()}.csv"`);
    res.send(csv);
  }
}

